#!/usr/bin/env node
// generate-elevenlabs-dialogue — multi-speaker variant of the audio gen
// script. Scenes can mix narrator + student lines via inline tags:
//
//   "Capital N is the count. [STUDENT]Wait — why's it capital?[/STUDENT]
//    Great question. Capital N means..."
//
// The tag parser splits the text into segments tagged by speaker; each
// segment is generated by the appropriate ElevenLabs voice; the audio
// is concatenated, the alignment data is merged with cumulative offsets,
// and the final MP3 + alignment.json are written as if the scene had
// been a single utterance.
//
// Supported tags (case-insensitive):
//   [NARRATOR]...[/NARRATOR]   — explicit narrator block (default if untagged)
//   [STUDENT]...[/STUDENT]     — student/learner character voice
//
// Usage:
//   ELEVENLABS_API_KEY=... node scripts/generate-elevenlabs-dialogue.mjs \
//     <manifest-json> [scene-id] \
//     --narrator-voice=<id> --student-voice=<id>
//
// Omit scene-id to process every scene in the manifest that contains a
// speaker tag (untagged scenes use the regular gen script's defaults).

import {mkdirSync, readFileSync, writeFileSync, existsSync} from 'node:fs';
import path from 'node:path';
import process from 'node:process';

const args = process.argv.slice(2);
const positional = args.filter((a) => !a.startsWith('--'));
const manifestPath = positional[0];
const onlySceneId = positional[1];

const narratorVoice = args.find((a) => a.startsWith('--narrator-voice='))?.split('=')[1];
const studentVoice = args.find((a) => a.startsWith('--student-voice='))?.split('=')[1];
const dryRun = args.includes('--dry-run');
const apiKey = process.env.ELEVENLABS_API_KEY;

if (!manifestPath || !narratorVoice || !studentVoice || !apiKey) {
	console.error('Usage: node scripts/generate-elevenlabs-dialogue.mjs <manifest> [scene-id] --narrator-voice=<id> --student-voice=<id>');
	console.error('Env:   ELEVENLABS_API_KEY required');
	process.exit(1);
}

const NARRATOR_SETTINGS = {stability: 0.5, similarity_boost: 0.75, style: 0.3, use_speaker_boost: true, speed: 1.0};
// Student voice (jyYV4jm5…) at the "curious" profile that won the A/B test:
// slightly lower stability + higher style than the narrator so questions
// lift naturally and reactive lines like "Wait — really?" feel alive.
const STUDENT_SETTINGS = {stability: 0.40, similarity_boost: 0.75, style: 0.45, use_speaker_boost: true, speed: 1.0};

// Parse text with [NARRATOR]/[STUDENT] tags into ordered segments.
// Text outside any tag is treated as narrator (default speaker).
const parseDialogue = (text) => {
	const segments = [];
	const re = /\[(NARRATOR|STUDENT)\](.+?)\[\/\1\]/gis;
	let lastIdx = 0;
	let m;
	while ((m = re.exec(text)) !== null) {
		const untagged = text.slice(lastIdx, m.index).trim();
		if (untagged) segments.push({speaker: 'narrator', text: untagged});
		segments.push({speaker: m[1].toLowerCase(), text: m[2].trim()});
		lastIdx = m.index + m[0].length;
	}
	const trailing = text.slice(lastIdx).trim();
	if (trailing) segments.push({speaker: 'narrator', text: trailing});
	return segments;
};

const hasDialogueTags = (text) => /\[(NARRATOR|STUDENT)\]/i.test(text);

const callTTS = async (text, voiceId, settings) => {
	const r = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}/with-timestamps`, {
		method: 'POST',
		headers: {'Content-Type': 'application/json', 'xi-api-key': apiKey},
		body: JSON.stringify({
			text,
			model_id: 'eleven_turbo_v2_5',
			voice_settings: settings,
		}),
	});
	if (!r.ok) throw new Error(`HTTP ${r.status}: ${await r.text()}`);
	return r.json();
};

const generateScene = async (scene) => {
	const segments = parseDialogue(scene.text);
	console.log(`\nScene "${scene.id}": ${segments.length} dialogue segments`);
	segments.forEach((s, i) => {
		console.log(`  [${i}] ${s.speaker.padEnd(10)} ${s.text.length}c: "${s.text.slice(0, 60)}${s.text.length > 60 ? '...' : ''}"`);
	});

	if (dryRun) {
		console.log('  (dry run — no audio generated)');
		return;
	}

	const audioBuffers = [];
	const mergedChars = [];
	const mergedStarts = [];
	const mergedEnds = [];
	let timeOffset = 0;

	for (let i = 0; i < segments.length; i++) {
		const seg = segments[i];
		const voiceId = seg.speaker === 'student' ? studentVoice : narratorVoice;
		const settings = seg.speaker === 'student' ? STUDENT_SETTINGS : NARRATOR_SETTINGS;
		process.stdout.write(`  segment ${i + 1}/${segments.length} (${seg.speaker}) ... `);
		try {
			const payload = await callTTS(seg.text, voiceId, settings);
			const buf = Buffer.from(payload.audio_base64, 'base64');
			audioBuffers.push(buf);

			const a = payload.alignment || {};
			const chars = a.characters || [];
			const starts = a.character_start_times_seconds || [];
			const ends = a.character_end_times_seconds || [];
			for (let j = 0; j < chars.length; j++) {
				mergedChars.push(chars[j]);
				mergedStarts.push(starts[j] + timeOffset);
				mergedEnds.push(ends[j] + timeOffset);
			}
			const lastEnd = ends.length > 0 ? ends[ends.length - 1] : 0;
			// Insert a small pause character between speaker switches (50ms)
			// so the conversation feels natural rather than rapid-fire.
			if (i < segments.length - 1) {
				const isSpeakerSwitch = segments[i + 1].speaker !== seg.speaker;
				const pauseDur = isSpeakerSwitch ? 0.15 : 0.05;
				mergedChars.push(' ');
				mergedStarts.push(lastEnd + timeOffset);
				mergedEnds.push(lastEnd + timeOffset + pauseDur);
				timeOffset += lastEnd + pauseDur;
			} else {
				timeOffset += lastEnd;
			}
			console.log(`OK (${buf.length}b, ${lastEnd.toFixed(2)}s)`);
		} catch (e) {
			console.error(`FAIL: ${e.message}`);
			throw e;
		}
	}

	const finalAudio = Buffer.concat(audioBuffers);
	const outputPath = scene.audioFile;
	mkdirSync(path.dirname(outputPath), {recursive: true});
	writeFileSync(outputPath, finalAudio);

	const alignmentPath = outputPath.replace(/\.mp3$/, '.alignment.json');
	writeFileSync(alignmentPath, JSON.stringify({
		characters: mergedChars,
		character_start_times_seconds: mergedStarts,
		character_end_times_seconds: mergedEnds,
	}, null, 2));

	console.log(`  wrote ${outputPath} (${finalAudio.length} bytes, ${timeOffset.toFixed(2)}s total)`);
};

const manifest = JSON.parse(readFileSync(manifestPath, 'utf8'));
const scenesToProcess = onlySceneId
	? manifest.scenes.filter((s) => s.id === onlySceneId)
	: manifest.scenes.filter((s) => hasDialogueTags(s.text));

if (scenesToProcess.length === 0) {
	console.log('No scenes with dialogue tags found. (Use [STUDENT]...[/STUDENT] to author multi-speaker lines.)');
	process.exit(0);
}

console.log(`Processing ${scenesToProcess.length} dialogue scene(s) from ${manifestPath}`);
console.log(`Narrator voice: ${narratorVoice}`);
console.log(`Student voice:  ${studentVoice}`);

for (const scene of scenesToProcess) {
	await generateScene(scene);
}

console.log('\nDone. Run sync-voiceover-assets + auto-sync-bullets/reveals/captions afterwards as usual.');
